var skillName = "active.use_motion_scanner";
var skillOpt = Templates.All<SkillTemplate>().FirstOrDefault(s => s.name == skillName);
Assert.NotNull(skillOpt, $"Skill/Perk '{skillName}' should exist");
skillOpt

var handlers = skillOpt.EventHandlers;
Assert.NotNull(handlers, "EventHandlers should not be null");
Assert.True(handlers.Count > 0, "Should have at least one EventHandler");
var handler = handlers.FirstOrDefault(h => h._type == "Scanner");
Assert.NotNull(handler, $"Should find Scanner EventHandler");
handler

var fieldValue = handler.Range;
Assert.NotNull(fieldValue, "Range should be populated");
fieldValue
